import React, { useState } from 'react';
import { useNavigate, useLocation, Link } from 'react-router-dom';
import axios from 'axios';

const Auth = () => {
    const navigate = useNavigate();
    const location = useLocation();

    const isSignIn = location.pathname === '/signin';

    // Different backgrounds for Sign In and Sign Up
    const signInBg = "https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1920&q=80"; // Darker, mysterious theme
    const signUpBg = "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=1920&q=80"; // Original explorer theme

    const bg_image = isSignIn ? signInBg : signUpBg;

    // Shared States
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState("");

    // Sign In States
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);

    // Sign Up States
    const [formData, setFormData] = useState({
        username: "",
        email: "",
        password: "",
        confirmPassword: "",
        phone: "",
        agreeTerms: false
    });
    const [strength, setStrength] = useState({ score: 0, label: "", color: "transparent" });

    const toggleAuth = () => {
        navigate(isSignIn ? '/signup' : '/signin');
        resetForm();
    };

    const resetForm = () => {
        setError("");
        setSuccess("");
        setEmail("");
        setPassword("");
        setFormData({
            username: "", email: "", password: "", confirmPassword: "", phone: "", agreeTerms: false
        });
        setStrength({ score: 0, label: "", color: "transparent" });
    };

    const evaluatePassword = (pass) => {
        let score = 0;
        if (!pass) return { score: 0, label: "", color: "transparent" };
        if (pass.length >= 8) score++;
        if (/[a-zA-Z]/.test(pass)) score++;
        if (/[0-9]/.test(pass)) score++;
        if (/[^A-Za-z0-9]/.test(pass)) score++;

        const levels = [
            { score: 25, label: "Weak", color: "#ff4d4d" },
            { score: 50, label: "Fair", color: "#ffa500" },
            { score: 75, label: "Good", color: "#2ecc71" },
            { score: 100, label: "Strong", color: "#1db954" }
        ];
        return levels[score - 1] || levels[0];
    };

    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        const val = type === 'checkbox' ? checked : value;

        if (!isSignIn) {
            setFormData({ ...formData, [name]: val });
            if (name === "password") setStrength(evaluatePassword(val));
        }
    };

    const handleSignIn = async (e) => { /* ... same as before ... */ 
        e.preventDefault();
        setLoading(true);
        setError("");
        setSuccess("");

        try {
            const formDataApi = new FormData();
            formDataApi.append('email', email);
            formDataApi.append('password', password);

            const response = await axios.post("https://lexluther.alwaysdata.net/api/signin", formDataApi);

            if (response.data.user || response.data.success) {
                setSuccess("Sign in successful!");
                localStorage.setItem("user", JSON.stringify(response.data.user));
                setTimeout(() => navigate("/"), 1500);
            } else {
                setError(response.data.message || "Invalid credentials");
            }
        } catch (err) {
            setError(err?.response?.data?.message || "Sign in failed.");
        } finally {
            setLoading(false);
        }
    };

    const handleSignUp = async (e) => { /* ... same as before ... */ 
        e.preventDefault();
        setError("");

        if (formData.password !== formData.confirmPassword) {
            setError("Passwords do not match.");
            return;
        }
        if (formData.password.length < 8 || !/^(?=.*[a-zA-Z])(?=.*\d)(?=.*[^A-Za-z0-9]).+$/.test(formData.password)) {
            setError("Password must be 8+ characters with letters, numbers & symbols.");
            return;
        }
        if (!formData.agreeTerms) {
            setError("You must agree to the Terms & Conditions.");
            return;
        }

        setLoading(true);
        try {
            const data = new FormData();
            data.append('username', formData.username);
            data.append('email', formData.email);
            data.append('password', formData.password);
            data.append('phone', formData.phone);

            await axios.post("https://lexluther.alwaysdata.net/api/signup", data);

            setSuccess("Account created successfully! Redirecting...");
            setTimeout(() => navigate("/signin"), 2000);
        } catch (err) {
            if (err?.response?.status === 409) {
                setError("Username already taken.");
            } else {
                setError(err?.response?.data?.message || "Signup failed.");
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="hero-container" style={{ backgroundImage: `url(${bg_image})` }}>
            <div className="vignette"></div>

            <div className="glass-card" style={{
                position: 'relative',
                zIndex: 2,
                background: 'rgba(255, 255, 255, 0.12)',
                backdropFilter: 'blur(15px)',
                borderRadius: '30px',
                padding: '50px 40px',
                width: '100%',
                maxWidth: '420px',
                color: '#fff',
                boxShadow: '0 20px 40px rgba(0,0,0,0.4)',
                textAlign: 'center'
            }}>
                <h2 style={{ color: '#FFD700', letterSpacing: '3px', textTransform: 'uppercase', fontSize: '1rem' }}>
                    Pathfinder
                </h2>

                <h1 style={{ fontSize: '2.3rem', margin: '10px 0 8px' }}>
                    {isSignIn ? "Welcome Back" : "Join the Journey"}
                </h1>
                <p style={{ opacity: 0.8, marginBottom: '30px' }}>
                    {isSignIn ? "Continue your journey" : "Create your account and start exploring"}
                </p>

                {isSignIn && (
                    <button
                        onClick={() => navigate('/signup')}
                        style={{
                            position: 'absolute',
                            top: '25px',
                            right: '25px',
                            background: 'transparent',
                            border: '1px solid rgba(255,255,255,0.4)',
                            color: '#fff',
                            padding: '8px 18px',
                            borderRadius: '30px',
                            cursor: 'pointer',
                            fontSize: '0.85rem'
                        }}
                    >
                        Log Out
                    </button>
                )}

                <form onSubmit={isSignIn ? handleSignIn : handleSignUp}>
                    {error && <p style={{ color: '#ff4d4d', margin: '12px 0' }}>{error}</p>}
                    {success && <p style={{ color: '#1db954', margin: '12px 0' }}>{success}</p>}

                    {/* Form Fields - Same as previous version */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                        {!isSignIn && (
                            <input style={inputStyle} type="text" name="username" placeholder="Username" value={formData.username} onChange={handleChange} required />
                        )}

                        <input
                            style={inputStyle}
                            type="email"
                            placeholder="Email Address"
                            value={isSignIn ? email : formData.email}
                            onChange={isSignIn ? (e) => setEmail(e.target.value) : handleChange}
                            name={!isSignIn ? "email" : undefined}
                            required
                        />

                        {!isSignIn && (
                            <input style={inputStyle} type="tel" name="phone" placeholder="Phone Number (Optional)" value={formData.phone} onChange={handleChange} />
                        )}

                        <div style={{ position: 'relative' }}>
                            <input
                                style={inputStyle}
                                type={showPassword ? "text" : "password"}
                                placeholder={isSignIn ? "Password" : "Create Password"}
                                value={isSignIn ? password : formData.password}
                                onChange={isSignIn ? (e) => setPassword(e.target.value) : handleChange}
                                name={!isSignIn ? "password" : undefined}
                                required
                            />
                            <button type="button" onClick={() => setShowPassword(!showPassword)} style={{ position: 'absolute', right: '15px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: '#FFD700', cursor: 'pointer' }}>
                                {showPassword ? "Hide" : "Show"}
                            </button>
                        </div>

                        {!isSignIn && formData.password && (
                            <div style={{ textAlign: 'left', marginTop: '-5px' }}>
                                <div style={{ height: '6px', background: 'rgba(255,255,255,0.2)', borderRadius: '3px' }}>
                                    <div style={{ width: `${strength.score}%`, height: '100%', backgroundColor: strength.color, borderRadius: '3px' }} />
                                </div>
                                <span style={{ color: strength.color, fontSize: '0.85rem' }}>{strength.label}</span>
                            </div>
                        )}

                        {!isSignIn && (
                            <input style={inputStyle} type="password" name="confirmPassword" placeholder="Confirm Password" value={formData.confirmPassword} onChange={handleChange} required />
                        )}
                    </div>

                    {!isSignIn && (
                        <div style={{ margin: '20px 0', textAlign: 'left' }}>
                            <input type="checkbox" id="agreeTerms" name="agreeTerms" checked={formData.agreeTerms} onChange={handleChange} style={{ marginRight: '8px' }} />
                            <label htmlFor="agreeTerms" style={{ fontSize: '0.9rem' }}>
                                I agree to the <Link to="/terms" style={{ color: '#FFD700' }}>Terms & Conditions</Link>
                            </label>
                        </div>
                    )}

                    <button type="submit" style={btnStyle} disabled={loading}>
                        {loading ? (isSignIn ? "Signing In..." : "Creating Account...") : (isSignIn ? "SIGN IN" : "CREATE ACCOUNT")}
                    </button>

                    <p style={{ marginTop: '25px', fontSize: '0.95rem' }}>
                        {isSignIn ? "Don't have an account?" : "Already have an account?"}{' '}
                        <Link to="#" onClick={toggleAuth} style={{ color: '#FFD700', fontWeight: 'bold' }}>
                            {isSignIn ? "Create one" : "Sign In"}
                        </Link>
                    </p>
                </form>
            </div>
        </div>
    );
};

const inputStyle = {
    padding: '15px',
    borderRadius: '12px',
    border: '1px solid rgba(255,255,255,0.2)',
    background: 'rgba(255, 255, 255, 0.1)',
    color: '#fff',
    outline: 'none',
    width: '100%'
};

const btnStyle = {
    width: '100%',
    padding: '15px',
    marginTop: '10px',
    borderRadius: '50px',
    border: 'none',
    background: 'linear-gradient(90deg, #FFD700, #f39c12)',
    color: '#000',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '1.05rem'
};

export default Auth;
